# https://metabase.docurba.beta.gouv.fr/question/514-module-enquete-zan-modifications-simplifiees-de-scot-avec-un-1er-evenement-26-08-2020?departement_filter=&procedure_id_filter=
SCOTS_WITH_FIRST_EVENT_SQL = r"""
        with results as (
            select
            procedures.collectivite_porteuse_id AS "collectivite_code_id",
            procedures.id AS "procedure_id",
            departements_agreges.departements as "departements",
            surveys.id as "survey_id"
            FROM
            PROCEDURES
            LEFT JOIN (
                SELECT
                procedures_perimetres.procedure_id,
                array_agg(DISTINCT procedures_perimetres.departement) AS departements
                FROM
                procedures_perimetres
                WHERE
                procedures_perimetres.departement != '' and procedures_perimetres.departement != 'UNKWN'
                GROUP BY
                procedure_id
            ) AS departements_agreges ON PROCEDURES.id = departements_agreges.procedure_id
            -- On récupère la date du TOUT PREMIER événement (le plus ancien)
            LEFT JOIN (
            SELECT
                procedure_id,
                MIN(doc_frise_events.date_iso) AS date_premier_event
            FROM doc_frise_events
            WHERE doc_frise_events.is_valid = TRUE
            GROUP BY procedure_id
            ) AS premier_evenement ON premier_evenement.procedure_id = procedures.id
            LEFT JOIN core_collectivite ON procedures.collectivite_porteuse_id = core_collectivite.code_insee_unique,
            surveys_survey as surveys
            WHERE
            PROCEDURES.archived = FALSE
            AND procedures.type = 'Modification simplifiée'
            AND procedures.doc_type IN ('SCOT')
            -- Cas 1 : le premier événement doit être après le 22 août 2020 donc 1 an avant la loi C&R
            AND (
            (premier_evenement.date_premier_event > '2020-08-22')
            OR
                -- ou Cas 2 : Elle n'a ABSOLUMENT AUCUN événement ET elle a été créée après le 22/08/2020 : pour cela je dois utiliser last_updated_at car il y a trop de procédures sans created_at
            (procedures.last_updated_at > '2020-08-22'
            AND NOT EXISTS (
                SELECT 1
                FROM doc_frise_events
                WHERE doc_frise_events.procedure_id = PROCEDURES.id
                AND doc_frise_events.is_valid = TRUE
            )
            )
            )
            and surveys.name = 'zan_03_2026'
            and exists(
                select 1 from core_collectivite where core_collectivite.code_insee_unique = procedures.collectivite_porteuse_id
            )
        )
        insert into surveys_proceduresurvey (collectivite_code_id, procedure_id, survey_id, created_at, departements)
        select collectivite_code_id, procedure_id, survey_id, current_timestamp, departements
        from results;
"""

