# https://metabase.docurba.beta.gouv.fr/question/520-module-enquete-zan-procedures-principales-hors-scot-en-cours-ou-opposables-en-retirant-le-statut-precedent-sans-date-approbation-26-08-2021-et-sans-date-arret-26-08-2021?departement_filter=&procedure_id_filter=
ONGOING_OR_ENFORCEABLE = r"""
        with results as (
            select
            procedures.collectivite_porteuse_id AS "collectivite_code_id",
            procedures.id AS "procedure_id",
            departements_agreges.departements as "departements",
            surveys.id as "survey_id"
            FROM
            PROCEDURES
            LEFT JOIN (
                SELECT
                procedures_perimetres.procedure_id,
                array_agg(DISTINCT procedures_perimetres.departement) AS departements
                FROM
                procedures_perimetres
                WHERE
                procedures_perimetres.departement != '' and procedures_perimetres.departement != 'UNKWN'
                GROUP BY
                procedure_id
            ) AS departements_agreges ON PROCEDURES.id = departements_agreges.procedure_id
            LEFT JOIN (
                SELECT
                doc_frise_events.procedure_id,
                MAX(
                    CASE
                    WHEN doc_frise_events.type ~* '\yapprobation\y' THEN doc_frise_events.date_iso
                    ELSE NULL
                    END
                ) AS date_approbation
                FROM
                doc_frise_events
                WHERE
                doc_frise_events.is_valid = TRUE
                GROUP BY
                doc_frise_events.procedure_id
            ) AS evenement_approbation ON procedures.id = evenement_approbation.procedure_id -- On définit la date d'arrêt (on regarde la plus récente si plusieurs - choix arbitraire)
            LEFT JOIN (
                SELECT
                procedure_id,
                MAX(doc_frise_events.date_iso) AS date_arret
                FROM
                doc_frise_events
                WHERE
                doc_frise_events.is_valid = TRUE
                AND doc_frise_events.type ~* 'Arrêt de projet'
                GROUP BY
                procedure_id
            ) AS evenement_arret ON evenement_arret.procedure_id = procedures.id
            LEFT JOIN core_collectivite ON procedures.collectivite_porteuse_id = core_collectivite.code_insee_unique,
            surveys_survey as surveys
            WHERE
            PROCEDURES.archived = FALSE
            AND PROCEDURES.is_principale = TRUE --AND procedures.status IN ('en cours', 'opposable')
            AND procedures.type NOT IN ('Abrogation')
            AND procedures.doc_type NOT IN ('SCOT')
            AND (
                -- soit le statut est en cours soit le statut est opposable mais dans ces cas là il faut qu'il le soit aussi dans la table perimètre pour au moins une ligne pour une même procédure_id
                PROCEDURES.STATUS = 'en cours'
                OR (
                PROCEDURES.STATUS = 'opposable'
                AND EXISTS (
                    SELECT
                    1
                    FROM
                    procedures_perimetres pp
                    WHERE
                    pp.procedure_id = PROCEDURES.id
                    AND pp.opposable = TRUE
                )
                )
            ) -- 1. Exclure les procédures avec une date_approbation < 22/08/2021
            AND (
                evenement_approbation.date_approbation > '2021-08-22'
                OR evenement_approbation.date_approbation IS NULL
            ) -- 2. Exclure les procédures si date_arret < 22/08/2021
            AND (
                evenement_arret.date_arret > '2021-08-22'
                OR evenement_arret.date_arret IS NULL
            )
            and surveys.name = 'zan_03_2026'
            and exists(
                select 1 from core_collectivite where core_collectivite.code_insee_unique = procedures.collectivite_porteuse_id
            )
        )
        insert into surveys_proceduresurvey (collectivite_code_id, procedure_id, survey_id, created_at, departements)
        select collectivite_code_id, procedure_id, survey_id, current_timestamp, departements
        from results;
"""

